"""
MKT Original Commentary — 1 Samuel chapters 15–16
Run: python3 scripts/zc-original-1samuel-15-16.py

Source data used:
- data/interlinear/1samuel.json
- data/translation/glossary-hebrew.json (ḥērem, nāḥam, šāmaʿ, lēḇ, rûaḥ)
- data/translation/notes/1samuel.json (ch15 v9 token notes)
- data/translation/draft/mediating/1samuel.json (MKT text for quoting)

Key decisions in this range:
- ḥērem (H2763): rendered "devote to destruction" / "devoted to destruction"; not "curse" — the root is the ban/dedication-to-YHWH concept, not mere imprecation
- nāḥam (H5162): rendered "regret" / "change his mind" — the paradox between v11 (YHWH regrets) and v29 (the Eternal One does not change his mind) is left in tension; both are authentic
- šāmaʿ (H8085): "obey" in v22 captures the Hebrew semantic overlap of hearing-and-acting; the MKT's "obedience to his voice" preserves the auditory origin
- māʾas (H3988): "reject" — same verb used of Saul rejecting YHWH's word (v23) and YHWH rejecting Saul as king (v23, 26); the symmetry is deliberate
- rûaḥ YHWH (H7307+H3068): "Spirit of the LORD" — the abrupt departure from Saul and the powerful coming upon David marks a transfer of covenant empowerment
- ṣālaḥ (H6743) in 16:13: "came powerfully upon" — the verb denotes sudden, effective action; same root used in 10:6, 10 for Saul
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

SAMUEL1 = {
  "15": {
    "1": '<p><strong>šālaḥ</strong> + <strong>māšaḥ</strong> — <em>šālaḥ</em> (H7971, sent) and <em>māšaḥ</em> (H4886, anoint) together frame the covenant commission: Samuel acted as YHWH\'s agent, and Saul\'s kingship is entirely derived authority. The verse grounds the following command in that original commissioning — Saul\'s failure to obey is therefore a failure of covenant stewardship, not merely military insubordination.</p>',
    "2": '<p><strong>pāqad</strong> (H6485) — "I remember" translates <em>pāqadtî</em>, but the verb\'s range includes "attend to, muster, call to account." YHWH is not merely recalling history; he is acting on a standing account. The same verb governs covenant blessing and curse (Exod 20:5). <em>ʾăšer śām lô derek bəʿălōtô mimmiṣrāyim</em> — the relative clause grounds the command in the Exodus narrative: Amalek attacked from behind on the road (Exod 17:8-16; Deut 25:17-19), and that covenantal score is now being settled.</p>',
    "3": '<p><strong>ḥērem</strong> (H2763) — the root appears three times in vv3–9 as the pivotal term. <em>ḥāramtāh</em> means "devote to destruction" — the total consecration of enemy spoil to YHWH, leaving nothing for the victor. The ḥērem is not mere slaughter but a ritual act asserting YHWH\'s sole ownership of the victory. The list ("man and woman, child and nursing infant, ox and sheep, camel and donkey") is total; no exception is authorized. Saul\'s selective application of it is the crux of ch15.</p>',
    "4": '<p>Verse reports the muster at Telaim (<em>ṭəlāʾîm</em>). The numerical data (200,000 + 10,000 of Judah separately enumerated) reflects the administrative levy structure; Judah\'s separate count anticipates the coming split. No Hebrew lexical issue; the verse is narrative preparation.</p>',
    "5": '<p><em>wayāreb</em> (H693, from <em>ʾārab</em>) — "set an ambush." The same root governs Amalek\'s original attack (Exod 17:8 context; Deut 25:18 — Amalek "ambushed" Israel on the road). Saul uses Amalek\'s own tactical signature against them — the narrative symmetry is probably deliberate.</p>',
    "6": '<p><strong>ḥesed</strong> (H2617) — "loyalty" in the MKT. Saul warns the Kenites away because they "showed loyalty (<em>ḥesed</em>) to all Israel when they came up from Egypt." The Kenites\' covenant-loyalty is honored; this is the positive use of ḥesed — covenant-faithfulness that earns protection. The contrast with Saul\'s own covenant-unfaithfulness in what follows is implicit but pointed.</p>',
    "7": '<p>Geographic extent: "from Havilah to the approach of Shur, which lies east of Egypt." The breadth signals total victory — the same formula appears in Gen 25:18 for Ishmael\'s territory. The ḥērem command has been executed on the land; only Agag and the best livestock remain.</p>',
    "8": '<p><strong>wayyiḥyē</strong> with <strong>Agag</strong> — "He captured Agag alive" (<em>ḥay</em>, living). The specific mention of Agag\'s survival against the ḥērem command signals the violation immediately after the summary of general compliance. <em>wayyaḥărem</em> (he devoted to destruction) in the second half creates the contrast: the rest received the ḥērem; Agag did not.</p>',
    "9": '<p><strong>ʾāḇāh</strong> (H14) — "refused" (<em>lōʾ ʾāḇû</em>, they would not consent/were unwilling). The verb denotes active refusal, not oversight. The translation notes flag <em>ḥāmal</em> (H2550, spared — "to commiserate, have compassion") applied to Agag and the livestock: the emotion that overrode the command was pity for valuable things. <em>miśmān</em> (fatlings) and <em>ṭōḇ</em> (good/best) are the categories spared. What was <em>nimrāṣ</em> (thin, despised) was devoted. The inversion — keeping the good, destroying the inferior — reveals that the ḥērem was treated as a waste-disposal mechanism, not a sacred act.</p>',
    "10": '<p>Formulaic prophetic reception: <em>wayhî dəḇar YHWH ʾel šəmûʾēl lēʾmōr</em> — "Then the word of the LORD came to Samuel, saying." The same formula governs the commissioning of prophets (1 Kgs 17:2; Jer 1:4). Its appearance here marks Samuel as the covenant mediator who will pronounce the formal verdict.</p>',
    "11": '<p><strong>nāḥam</strong> (H5162) — the theologically dense verb: "I regret (<em>niḥamtî</em>) that I made Saul king." The Niphal of <em>nāḥam</em> denotes being moved with sorrow to the point of changing one\'s course. It is used of YHWH relenting from judgment (Exod 32:14; Jon 3:10) and here of regretting a positive act. The same root appears in v29 and v35 with the opposite claim — that YHWH does not <em>nāḥam</em>. The paradox is not a contradiction but a theological calibration: YHWH genuinely responds to the moral reality of human choice (here, v11), yet his ultimate purposes and character are not subject to reversal (v29). Both truths must be held.</p><p><em>wayyiḥar lišmûʾēl</em> — "Samuel was troubled/angry" (root <em>ḥārāh</em>, H2734, to burn/be kindled). The same word used for YHWH\'s anger in many texts; Samuel\'s reaction mirrors the divine response. <em>wayyizʿaq ʾel YHWH kol hallaylāh</em> — he "cried out to YHWH all night" — the intensity is extraordinary; prophetic intercession at its most urgent.</p>',
    "12": '<p><em>wayyāṣeḇ lô yād</em> — "he set up a monument for himself" (<em>yād</em> literally "hand," but used for a stele or memorial inscription — cf. 2 Sam 18:18, "Absalom\'s monument"). The self-erection of a monument before any accounting to Samuel or YHWH characterizes Saul\'s trajectory: victory is converted into personal honor rather than covenant obedience. Carmel-then-Gilgal: the movement from monument-building to the site of sacrifice shows Saul\'s priorities reversed.</p>',
    "13": '<p><em>bārûḵ ʾattāh laYHWH</em> — Saul\'s greeting formula ("Blessed are you by the LORD") is a covenant-blessing invocation; its use in the context of disobedience is ironic. <em>hăqîmōtî ʾet dəḇar YHWH</em> — "I have carried out the LORD\'s command" — the perfect <em>hăqîmōtî</em> claims completed, accomplished action. Samuel\'s subsequent response demolishes this claim with auditory evidence.</p>',
    "14": '<p><em>qôl haṣṣōʾn</em> — "the sound/voice of the sheep." The noun <em>qôl</em> (H6963) means both "sound" and "voice." Samuel\'s question activates the auditory register that will become central in v22: YHWH values <em>šāmaʿ</em> (hearing-obeying) above sacrifice, and here the sound of the livestock testifies against Saul\'s claim to have heard.</p>',
    "15": '<p>Saul deflects by identifying agency: "the <em>people</em> brought them." The shift from "I" (v13) to "the people" (v15) is the grammar of blame-shifting. The rationale offered — "to sacrifice to YHWH your God" — is liturgically framed but the possessive "your God" subtly distances Saul from covenant ownership. The best were spared; the rest destroyed: the same vocabulary as v9.</p>',
    "16": '<p><em>wayyōʾmer šəmûʾēl ʾel šāʾûl herpē</em> — "Samuel said, Stop" (<em>herpē</em>, from <em>rāpāh</em>, H7503, to let go, desist). The command to be silent before hearing the prophetic word is itself a posture of submission. Saul\'s immediate "Speak" (<em>daббēr</em>) is formally compliant but the rest of the chapter shows he is not actually prepared to hear.</p>',
    "17": '<p><em>hălōʾ ʾim qāṭōn ʾattāh bəʿênêḵā</em> — "when you were small in your own eyes." <em>qāṭōn</em> (H6996, small/young) coupled with <em>bəʿênêḵā</em> (in your eyes/estimation) — self-assessment of insignificance. Samuel\'s rebuke reactivates the original condition of Saul\'s appointment: he was chosen precisely when he did not presume on his own importance (9:21). The contrast with the monument at Carmel (v12) is explicit.</p>',
    "18": '<p><em>derek</em> (way/mission) + <em>ḥāram</em> — "sent you on a mission (<em>derek</em>) with an explicit command: Go and completely destroy (<em>ḥāram</em>)." The noun <em>derek</em> (H1870) means both road and mission/way of acting; the whole chapter is about whether Saul followed the <em>derek</em> he was given. <em>derek hāʾămālēqî</em> (the way of the Amalekites) — annihilation was the specific, bounded command.</p>',
    "19": '<p><em>lāmmāh lōʾ šāmaʿtā bəqôl YHWH</em> — "Why did you not obey (<em>šāmaʿ</em>) the voice of YHWH?" The verb <em>šāmaʿ</em> (H8085) is both "hear" and "obey" — the two are not separable in Hebrew cognitive grammar. To hear YHWH\'s voice is to act on it; not acting proves not truly hearing. <em>wattaʿaś hārāʿ bəʿênê YHWH</em> — "you did what was evil in the eyes of YHWH" — the evaluative phrase is the narrative\'s own verdict formula (cf. Judges passim).</p>',
    "20": '<p>Saul\'s second self-defense uses <em>šāmaʿtî</em> (perfect: "I did obey/hear") but the verb is employed to mean only partial compliance. His claim to have "completely destroyed" the Amalekites (<em>ḥāramtî ʾet ʾămālēq</em>) is technically false: Agag lives. The speech demonstrates that Saul uses the covenant vocabulary without its substance.</p>',
    "21": '<p><em>wayyiqqaḥ hāʿām miššəlāl</em> — "the people took from the plunder." Saul again attributes agency to "the people" rather than himself. <em>rēʾšît haḥērem</em> — "the choicest of what had been devoted" — the phrase uses <em>rēʾšît</em> (H7225, first/best/choicest), the same word for firstfruits offered to YHWH. The irony: the best of the ḥērem was redirected from its dedicated purpose to a competing sacrificial use.</p>',
    "22": '<p><strong>šāmaʿ / šemen</strong> — Samuel\'s antithetical couplet: <em>hăḥāpēṣ laYHWH bəʿōlôt ûzəḇāḥîm kišmōaʿ bəqôl YHWH</em> — "Does YHWH delight in burnt offerings and sacrifices as in hearing/obeying his voice?" The comparison uses <em>kišmōaʿ</em> (a Qal infinitive construct with prefix kaf: "as in hearing"). The rhetorical question expects "no." <em>šāmaʿ</em> is placed against <em>zābaḥ</em> (sacrifice); then the positive formulation: <em>ṭôḇ šəmōaʿ mizzébaḥ</em> (better to hear/obey than sacrifice) and <em>ləhaqšîḇ méḥēleḇ ʾêlîm</em> (to attend/hearken than the fat of rams). <em>haqšêḇ</em> (H7181, Hiphil of <em>qāšaḇ</em>) denotes attentive listening — the posture of the disciple who gives the teacher full hearing. The verse is not anti-sacrifice but rather establishes that sacrifice without obedience is a category error.</p>',
    "23": '<p><strong>qesem / ʾāwen / tərāpîm</strong> — "rebellion is like the sin of divination (<em>qesem</em>); stubbornness is like wickedness (<em>ʾāwen</em>) and idolatry (<em>tərāpîm</em>)." <em>Qesem</em> (H7081) is a technical term for divination/witchcraft — specifically seeking guidance from spirits rather than YHWH. The comparison is structural: Saul\'s substitution of his own judgment for YHWH\'s command is functionally the same as consulting a medium. <em>Tərāpîm</em> (H8655) are household/fertility gods; the parallel equates stubbornness-over-YHWH\'s-command with idolatry. The key verb <em>māʾastāh</em> (Qal perfect, <em>māʾas</em> H3988, to reject/spurn) — "because you rejected the word of YHWH" — then governs the reversal: the same <em>māʾas</em> now applies to Saul: "he has rejected you as king."</p>',
    "24": '<p><em>ḥāṭāʾtî</em> (perfect: "I have sinned") — this is Saul\'s only explicit confession; the motivation he gives is <em>kî yārēʾtî ʾet hāʿām waʾešmaʿ bəqôlām</em> — "because I feared the people and listened to their voice." The verb <em>šāmaʿ bəqôl</em> (heard/obeyed the voice) echoes v22: Saul <em>šāmaʿ bəqôl hāʿām</em> (obeyed the people\'s voice) but not <em>šāmaʿ bəqôl YHWH</em> (YHWH\'s voice). The substitution of voices — people over God — is the lexical center of the chapter.</p>',
    "25": '<p><em>śāʾ nāʾ lăḥaṭṭāʾtî</em> — "forgive my sin" (<em>nāśāʾ ḥēṭʾ</em>, literally "carry/lift my sin" — the same idiom behind "bearing sins" in atonement theology; cf. Isa 53:12). Saul asks Samuel to be present at worship — the concern for public honor (<em>kāḇōd</em>) becomes explicit in v30.</p>',
    "26": '<p><em>lōʾ ʾāšûḇ ʿimmāḵ</em> — "I will not return/go back with you." <em>šûḇ</em> (H7725, to return/turn) carries covenantal weight — the same root governs repentance and return to YHWH throughout the prophetic corpus. Samuel\'s refusal to "return" with Saul enacts the verdict: the covenant path has been closed. The grounding: <em>kî māʾastāh ʾet dəḇar YHWH</em> (same as v23) — the rejection is mutual in structure.</p>',
    "27": '<p><em>kannap məʿîlô</em> — "the edge/hem of his robe." <em>Kānāp</em> (H3671) means both "wing" and "hem/edge" — the same word Ruth uses in 3:9 when she asks Boaz to "spread his garment" over her (invoking the goel). Here the tearing of the kānāp is an acted oracle. Samuel\'s <em>məʿîl</em> (H4598, robe/mantle) is the priestly robe of office; the tearing of what Saul grasps signals the tearing of what belongs to the anointed.</p>',
    "28": '<p><em>qāraʿ YHWH ʾet mamlᵉḵût yiśrāʾēl mēʿāliḵā hayyôm</em> — "The LORD has torn (<em>qāraʿ</em>) the kingdom of Israel from you today." <em>Qāraʿ</em> (H7167, to tear) echoes the torn robe — the acted sign (v27) becomes the verbal verdict (v28). <em>ûnətānāh lərēʿăḵā haṭṭôḇ mimmēḵā</em> — "and given it to your neighbor who is better than you." <em>Ṭôḇ mimmēḵā</em> (better than you) uses the same <em>ṭôḇ</em> that appeared in vv9 and 21 for the livestock Saul preserved. The contrast is sharp: Saul valued <em>ṭôḇ</em> livestock over the command; now a <em>ṭôḇ</em> man replaces him.</p>',
    "29": '<p><strong>nēṣaḥ yiśrāʾēl</strong> — "the Eternal One of Israel" (<em>nēṣaḥ</em>, H5331 — often "victory, glory, perpetuity"; the MKT\'s "Eternal One" captures the permanence meaning). <em>lōʾ yəšaqqqer</em> — "does not lie/deceive" (<em>šāqar</em>, H8266). <em>wəlōʾ yinnāḥēm</em> — "does not change his mind" (<em>nāḥam</em> again, same root as v11). The apparent contradiction with v11 (YHWH "regretted") is a theological claim, not an error: the <em>nāḥam</em> of v11 is genuine emotional response to a new moral state; the <em>lōʾ yinnāḥēm</em> of v29 asserts that YHWH\'s ultimate purposes — unlike human kings — are not subject to manipulation or reversal by human pressure. The verse is spoken precisely to Saul, who is about to appeal for public honor (v30).</p>',
    "30": '<p><em>kabbédnî nāʾ</em> — "honor me, please" (<em>kāḇēd</em>, H3513, to be heavy/honored). Saul\'s concern shifts from sin to reputation: <em>nəged ziqqənê ʿammî ûnəged yiśrāʾēl</em> (before the elders of my people and before Israel). The word <em>kāḇōd</em> (honor/glory) governs Saul\'s final concern; what he fears is loss of face, not loss of covenant standing. Samuel complies — not because the verdict has changed but to prevent disorder.</p>',
    "31": '<p>The narrative is laconic: <em>wayyiśtaḥû šāʾûl laYHWH</em> — "Saul worshipped the LORD." The single verb records the act without endorsement; Samuel\'s presence does not restore the relationship. The reader is meant to note the irony: Saul performs the worship he claimed to be preserving the livestock for.</p>',
    "32": '<p><em>maʿădannōt</em> — "hesitantly" (MT ʿdnt, variously read as "with careful steps" or "in chains" — the text is difficult; Targum has "in chains," LXX "trembling"). The MKT chooses "hesitantly." Agag\'s words <em>ʾāḵēn sār mar hammāwet</em> — "surely the bitter agony of death has passed" — are ambiguous: he may believe Samuel intends to spare him (ironic confidence), or he may be expressing relief that his captivity spared him death in battle. Either reading makes his execution in the next verse more abrupt.</p>',
    "33": '<p><em>šikkəlāh nashîm ḥarbaḵā</em> — "your sword has made women childless (<em>šikkēl</em>, H7921)." Samuel\'s pronouncement is lex talionis applied to royal scale: the verb <em>šikkēl</em> (to bereave of children) frames the execution as proportional justice, not arbitrary violence. <em>wayəšassēp šəmûʾēl ʾet ʾăḡāḡ</em> — "Samuel cut Agag down" (<em>šāsap</em>, H8158 — a hapax; probably "to hew to pieces"). The act is described as happening "before YHWH" (<em>lipnê YHWH</em>) at Gilgal — it is a ritual completion of the ḥērem, not a judicial execution.</p>',
    "34": '<p>The parting of ways: Samuel returns to Ramah; Saul to Gibeah. The geography underscores permanent separation — Samuel never comes to Gibeah (Saul\'s base), and Saul never comes to Ramah (Samuel\'s home). The covenant mediator and the failed king now exist in entirely separate spheres.</p>',
    "35": '<p><strong>nāḥam</strong> (third occurrence) — <em>wəNIHYAH niḥam YHWH kî himliḵ ʾet šāʾûl ʿal yiśrāʾēl</em> — "The LORD regretted that he had made Saul king over Israel." The verb closes the chapter as it opened it (v11). Samuel\'s grief (<em>ʾābal</em>, to mourn) mirrors YHWH\'s <em>nāḥam</em>; prophet and God share the same emotional response to Saul\'s failure. The chapter has moved from appointment (v1) to irreversible rejection (v35), and the bookend of <em>nāḥam</em> holds the arc together.</p>'
  },
  "16": {
    "1": '<p><em>ʿad māṯay ʾattāh miṯʾabbēl ʾel šāʾûl</em> — "How long will you mourn (<em>ʾābal</em>) for Saul?" The question is not reproach but a call to transition: grief is appropriate, but YHWH has moved on (<em>mēʾastîhû</em>, perfect — the rejection is complete and in the past). <em>mallēʾ qarnəḵā šāmen</em> — "fill your horn with oil" — the horn of anointing oil is the instrument of covenant installation; the command to fill it is the command to begin the new administration. <em>bāḥartî bānāyw</em> — "I have chosen among his sons" — <em>bāḥar</em> (H977, to choose/elect) is the covenant-election verb used of Israel (Deut 7:6) and of David consistently in later texts (Ps 89:3).</p>',
    "2": '<p><em>ʾêḵ ʾēlēḵ wəšāmaʿ šāʾûl wəhăraḡānî</em> — "How can I go? If Saul hears (<em>šāmaʿ</em>), he will kill me." Samuel\'s fear activates the <em>šāmaʿ</em> vocabulary again: Saul\'s hearing is dangerous. YHWH\'s answer is a concealment strategy — take a sacrifice. The practical accommodation of prophetic mission to political danger is notable: YHWH does not override the danger but provides a cover.</p>',
    "3": '<p><em>ûmāšaḥtāh lî ʾēt ʾăšer ʾōmar ʾēlêḵā</em> — "you are to anoint for me (<em>lî</em>) the one I indicate to you." The emphatic <em>lî</em> (for me / on my behalf) underscores that the anointing is YHWH\'s act performed through Samuel. The verb <em>ʾāmar</em> (to say/indicate) will be enacted in v12 — YHWH\'s speech-act identifies the individual.</p>',
    "4": '<p><em>wayyeḥerdû ziqnê hāʿîr liqrāʾtô</em> — "the elders of the town came trembling (<em>ḥārad</em>, H2729) to meet him." <em>Ḥārad</em> denotes trembling before what is awesome or dangerous — used of theophany encounters (Exod 19:16) and of the fear provoked by unexpected authority. Samuel\'s arrival provokes the same awe as a divine appearance; his prophetic office carries that weight.</p>',
    "5": '<p><em>hitqaddəšû ûḇāʾtem ʾittî bazzāḇaḥ</em> — "purify yourselves and come with me to the sacrifice." <em>Qāddēš</em> (Hithpael, to consecrate/purify oneself) is the ritual preparation for holy encounter — washing garments and abstaining (cf. Exod 19:10, 14). Samuel "consecrated" (<em>wayyəqaddēš</em>) Jesse and his sons specifically — a particular preparation beyond the communal purification, suggesting the sons are entering an especially sacred role.</p>',
    "6": '<p><em>wayyōʾmer šəmûʾēl ʾak nəged YHWH məšîḥô</em> — "Samuel thought: surely YHWH\'s anointed stands before him." <em>Nāḡad</em> (Niphal, H5048 — stand before, in the presence of) — Samuel\'s internal judgment uses "before him" (<em>nəgdô</em>) as if YHWH is already indicating Eliab. The assumption is based on physical stature — the same error that originally made Saul plausible (9:2). The word <em>māšîaḥ</em> (H4899, anointed one) here is used prospectively for whoever YHWH will designate; Samuel\'s pre-emptive use of it for Eliab is immediately corrected.</p>',
    "7": '<p><strong>lēḇ</strong> (H3820) — the chapter\'s central verse: <em>kî lōʾ ʾăšer yirʾeh hāʾādām kî hāʾādām yirʾeh lāʿênāyim waYHWH yirʾeh lallēḇ</em> — "for man sees what is visible to the eyes, but YHWH sees the heart (<em>lēḇ</em>)." The antithesis is structural: <em>hāʾādām/YHWH</em>, <em>ʿênāyim</em> (eyes, external) / <em>lēḇ</em> (heart, internal). <em>Lēḇ</em> in Hebrew psychology encompasses intellect, will, and moral orientation — not just emotion. YHWH\'s perception penetrates to the seat of character; human sight is limited to the external. The principle governs both David\'s selection and the entire theology of covenantal fidelity: what qualifies for election is not external advantage but the orientation of the inner self toward YHWH.</p><p><em>wayqahàr</em> (Qal imperfect with waw: "and the LORD looked at") — the verb <em>rāʾāh</em> (to see) is used for both sides, but YHWH\'s seeing penetrates where human seeing cannot. The verse also indirectly critiques Saul\'s appointment logic: Israel asked for a king who looked the part; YHWH now explicitly overrides that criterion.</p>',
    "8": '<p><em>wayqarāʾ yiššay ʾel ʾăḇînādāḇ</em> — Jesse presents seven sons in sequence. The verbal pattern is formulaic: each son passes before Samuel, Samuel says "the LORD has not chosen this one" (<em>lōʾ ḇāḥar YHWH bāzeh</em>), and the sequence continues. The repetition enacts the progressive elimination; each use of <em>bāḥar</em> (choose) anticipates the positive use in v12.</p>',
    "9": '<p>The same formula as v8 — <em>šammāh</em> (Shammah) passes, and <em>lōʾ ḇāḥar YHWH bāzeh</em>. The sequential rejection of Jesse\'s sons by name emphasizes that YHWH\'s election is not predictable by birth order, physical presence, or family standing — the first seven are each individually considered and passed over.</p>',
    "10": '<p><em>šibʿāh ḇānāyw</em> — "seven of his sons." Seven is the number of completion; that all seven pass before Samuel without divine selection sets up the reversal: the anointed is outside the expected frame entirely, absent from the formal presentation, tending sheep.</p>',
    "11": '<p><em>haqqāṭān</em> — "the youngest" (<em>qāṭān</em>, H6996 — same word used in 15:17 of Saul\'s original self-assessment: "when you were small in your own eyes"). The inversion is pointed: Saul was small and was made great; David is literally the smallest/youngest and will be chosen. <em>wəhinnēh rōʿeh baṣṣōʾn</em> — "he is tending the sheep (<em>rāʿāh</em>)" — the shepherd-image here is biographical; it will become the dominant metaphor for David\'s kingship (Ps 78:70-72; 2 Sam 5:2).</p>',
    "12": '<p><em>ʾadmōnî ʿim yəpê ʿênāyim wəṭôḇ rōʾî</em> — "ruddy, with beautiful eyes and handsome in appearance." <em>ʾAdmōnî</em> (H132, ruddy/reddish) is mentioned again in 17:42. The physical description comes after the theological principle of v7 — the narrator is not contradicting v7 but signaling that David\'s appearance is secondary to the divine word that follows. <em>wayōʾmer YHWH qûm mošḥēhû kî zeh hûʾ</em> — "YHWH said: Rise and anoint him, for this is the one" (<em>zeh hûʾ</em>). The divine word is monosyllabic and definitive: "this — he." No explanation of the inner qualities that qualified him; the election is pure divine prerogative.</p>',
    "13": '<p><strong>rûaḥ YHWH</strong> + <strong>ṣālaḥ</strong> — "the Spirit of the LORD came powerfully upon (<em>ṣālaḥ</em>, H6743) David from that day onward." <em>Ṣālaḥ</em> denotes effective, sudden action — the same root was used of the rûaḥ coming upon Saul (10:6, 10) and Samson (Judg 14:6, 19; 15:14). The force is invasive and transformative. The phrase <em>mēhayyôm hahûʾ wāmāʿlāh</em> (from that day onward) marks a permanent installation, not a transient experience — contrasted with v14 where the rûaḥ "departed (<em>sûr</em>) from Saul." <em>Māšaḥ bəqéreḇ ʾeḥāyw</em> — "anointed in the midst of his brothers" — the private ceremony before witnesses; public installation comes later (2 Sam 2:4; 5:3).</p>',
    "14": '<p><strong>sûr / rûaḥ rāʿāh</strong> — "the Spirit of the LORD departed (<em>sûr</em>, H5493) from Saul, and an evil/harmful spirit from the LORD tormented him." <em>Sûr</em> is the verb of departure/removal — the same root used when the ark was removed (4:21: <em>gālāh kāḇôd</em>, glory departed). The divine empowerment that Saul received at 10:10 is formally withdrawn. <em>Rûaḥ rāʿāh mēʾēt YHWH</em> — "a harmful spirit from the LORD" — the text does not identify this as a demonic being in later NT taxonomy; it is an affliction that YHWH permits/sends as part of the judicial withdrawal of protective presence. The juxtaposition of vv13-14 is deliberate: the rûaḥ moves from Saul to David in the same narrative moment.</p>',
    "15": '<p>Saul\'s servants explain the situation using the same vocabulary: <em>rûaḥ ʾĕlōhîm rāʿāh mǝḇaʿǝtteḵā</em> — "an evil spirit from God is troubling you" (<em>bāʿat</em>, H1204, to terrify/trouble). The servants recognize a theological reality — the spirit is from God — while seeking a practical remedy in music. The therapeutic use of music connects to the tradition of prophetic music (10:5) and the Psalms.</p>',
    "16": '<p><em>yôdēaʿ mənaggen</em> — "skilled/knowing in playing" (<em>yādaʿ</em> + <em>nāgan</em>). <em>Yādaʿ</em> (H3045, to know) with a skill denotes professional competence — the person who "knows how" to do something. <em>Nāgan</em> (H5059, to play a stringed instrument) — the lyre/kinnor. The servants propose a musical-therapeutic intervention; the logic connects physical performance to spiritual relief.</p>',
    "17": '<p><em>rəʾû nāʾ lî ʾîš mêṭîḇ lənaggen</em> — "find me a man who plays well" (literally "who does good in playing" — <em>mêṭîḇ</em> from <em>ṭôḇ</em>). The word <em>ṭôḇ</em> reappears: the man who is <em>ṭôḇ</em> at music will enter where the man the people wanted (tall, impressive) failed.</p>',
    "18": '<p><em>rāʾîtî bēn lǝyiššay bêt hallaḥmî yōdēaʿ nāḡēn</em> — "I know of a son of Jesse the Bethlehemite, skilled in playing." The servant\'s description of David is striking in its fullness: skilled in music, brave (<em>gibbôr ḥayil</em>), man of war (<em>ʾîš milḥāmāh</em>), prudent in speech (<em>nāḇôn dāḇār</em>), handsome (<em>ʾîš tōʾar</em>) — and above all, <em>waYHWH ʿimmô</em> — "the LORD is with him." The climactic phrase "YHWH is with him" is the theological summary that will recur throughout the David narrative (18:12, 14, 28). In contrast to the rûaḥ having departed from Saul, David\'s defining characteristic is divine presence.</p>',
    "19": '<p><em>šilḥû ʾēlay ʾet dāwid binkā hārōʿeh baṣṣōʾn</em> — "send me your son David, who tends the sheep." The royal summons still identifies David by his occupation — shepherd. The king who will replace Saul enters his orbit as a servant.</p>',
    "20": '<p>Jesse\'s gift: bread, wine, a young goat — the standard hospitality offering for a patron. The donkey as carrier signals the gift\'s weight and distance. David goes with the gift — as servant delivering tribute, not as heir presenting credentials.</p>',
    "21": '<p><em>wayʾahāḇēhû šāʾûl məʾōd</em> — "Saul loved him greatly (<em>ʾāhab</em> + <em>məʾōd</em>)." The intensity of the affection is recorded; it will intensify into lethal hatred. <em>wayhî lô nōśēʾ kēlîm</em> — "and became his armor-bearer." The armor-bearer role (nōśēʾ kēlîm) is one of high personal trust — the man who carries and hands the weapons of the king in battle.</p>',
    "22": '<p><em>yaqōm nāʾ dāwid lǝpānay</em> — "let David remain in my service" (literally "stand before me" — <em>ʿāmad lǝpānāyw</em>, the idiom of court attendance). Saul requests David specifically, and Jesse complies. The servant of Saul is the chosen of YHWH; the narrative tension of the next fifteen chapters is embedded in this single verse.</p>',
    "23": '<p><em>kəšeḇet rûaḥ hāʾĕlōhîm ʾel šāʾûl ... lāqaḥ dāwid ʾet hakkinnôr wəniggēn bəyādô</em> — "whenever the harmful spirit from God came upon Saul, David took the lyre and played." The temporal clause <em>kəšeḇet</em> (whenever/each time) marks a recurring pattern. <em>Kinnôr</em> (H3658, lyre/harp) is the instrument associated with worship and praise throughout the psalmic tradition — David\'s instrument. The therapeutic sequence: David plays → Saul is relieved → the harmful spirit departs. The verse closes ch16 by showing David already functioning as the agent of Saul\'s relief — the anointed king ministering to his predecessor who does not yet know who David truly is.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', '1samuel')
    merge_comm(existing, SAMUEL1)
    save_comm('mkt-original', '1samuel', existing)

    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / '1samuel.json'))
    all_ok = True
    for ch in [15, 16]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(existing.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(existing.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present ✓')

if __name__ == '__main__':
    main()
